_bb_rev_capt AS (
  FROM SELECT DATE_FORMAT( DATE_SUB(`date`, INTERVAL (DAYOFWEEK(`date`) - 1) DAY), '%Y-%m-%d' ) AS week_date, `base`.`country_name` AS country_name, c.`id` AS country_id, c.`short_name` AS country_short_name, `base`.`partner name` AS `partner name`, `base`.`Brand` AS Brand, `assigned_user` AS brand_assigned_user, `enforcement_codes`, (SUM(`asin_sales`)/SUM(`asin_potential_sales`)) AS bb_rev_capture, SUM(`asin_sales`) AS asin_sales, SUM(`asin_potential_sales`) AS asin_potential_sales, AVG(`asin_avg_bb`) AS asin_avg_bb FROM `_Daily_BB_Capture_ASIN_DV` AS base LEFT JOIN `_countries` AS c ON base.`country_name`=c.`name` WHERE `date` <= (CURRENT_DATE()-INTERVAL 2 DAY) GROUP BY 1,2,3,4,5,6,7,8 ORDER BY 1 DESC
),

_inv_share_pct AS (
  FROM SELECT DATE_FORMAT( DATE_SUB(`created_date`, INTERVAL (DAYOFWEEK(`created_date`) - 1) DAY), '%Y-%m-%d' ) AS week_date, c.`name` AS country_name, base.`country_id` AS country_id, c.`short_name` AS country_short_name, `base`.`partner name` AS `partner name`, `base`.`Brand` AS Brand, SUM(case WHEN `storefront_enforceable` in ('Authorized Seller', 'Official Seller Account') THEN `Units` ELSE 0 END)/SUM(`Units`) AS inv_share_pct FROM `_Limit_Buster_Inventory_DS` AS base LEFT JOIN `_countries` AS c ON base.`country_id`=c.`id` WHERE base.`isFBA` = 1 AND (`asin_bp_enforceable`=1 OR `asin_offers_scraper_enabled`=1) GROUP BY 1,2,3,4,5,6 ORDER BY 1 DESC
),

_map_comp_pct AS (
  FROM SELECT DATE_FORMAT( DATE_SUB(`scraped_date`, INTERVAL (DAYOFWEEK(`scraped_date`) - 1) DAY), '%Y-%m-%d' ) AS week_date, c.`name` AS country_name, base.`country_id` AS country_id, c.`short_name` AS country_short_name, `base`.`partner name` AS `partner name`, `base`.`Brand` AS Brand, (SUM(CASE WHEN (`offer_price`-`map`) >=0 THEN 1 ELSE 0 END) / SUM(CASE WHEN (`offer_price`-`map`) IS NOT NULL THEN 1 ELSE 0 END)) AS map_compliance_pct FROM `_Limit_Buster_Inventory_DS` AS base LEFT JOIN `_countries` AS c ON base.`country_id`=c.`id` WHERE (`asin_bp_enforceable`=1 OR `asin_offers_scraper_enabled`=1) AND `map`!=0 AND `storefront_enforceable`!='Official Seller Account' GROUP BY 1,2,3,4,5,6 ORDER BY 1 DESC
),

