_unsup_pct AS (
  FROM SELECT DATE_FORMAT(DATE_SUB(DATE_SUB(CURRENT_DATE(),INTERVAL 2 DAY), INTERVAL (DAYOFWEEK(DATE_SUB(CURRENT_DATE(),INTERVAL 2 DAY)) - 1) DAY),'%Y-%m-%d') AS week_date, `base`.`country_name` AS country_name, base.`country_id`, base.country_short_name, `base`.`partner name` AS `partner name`, `base`.`Brand` AS Brand, (SUM((CASE WHEN `Seller Category` = 'No BB' THEN 0 ELSE `LTM Potential Revenue` END))/SUM(`LTM Potential Revenue`)) AS unsuppressed_revenue_pct FROM `_Alter_Columns_1` AS base GROUP BY 1,2,3,4,5,6 ORDER BY 1 DESC
),

_SQL AS (
  FROM -- Preview input table SELECT CAST(a.`week_date` AS DATE) AS week_date, a.`country_name`, a.`country_id`, a.`country_short_name`, a.`partner name`, a.`Brand`, a.`brand_assigned_user`, a.`enforcement_codes`, b.unsuppressed_revenue_pct, a.`_bb_rev_capture`, a.`asin_sales`, a.`asin_potential_sales`, a.`asin_avg_bb`, c.`_inv_share_pct`, d.`map_compliance_pct`, ((b.unsuppressed_revenue_pct+a.`_bb_rev_capture`+c.`_inv_share_pct`+d.`map_compliance_pct`)/4) AS composite_score FROM `_bb_rev_capt` a LEFT JOIN  `_unsup_pct` b ON a.`week_date`=b.`week_date` AND a.`Brand`=b.`Brand` AND a.`country_id`=b.`country_id` AND a.`partner name`=b.`partner name` LEFT JOIN `_inv_share_pct` c ON a.`week_date`=c.`week_date` AND a.`Brand`=c.`Brand` AND a.`country_id`=c.`country_id` AND a.`partner name`=c.`partner name` LEFT JOIN _map_comp_pct d ON a.`week_date`=d.`week_date` AND a.`Brand`=d.`Brand` AND a.`country_id`=d.`country_id` AND a.`partner name`=d.`partner name` WHERE a.`week_date` <= (CURRENT_DATE()-INTERVAL 2 DAY)
),

_Brand_Control_Composite_Score_Weekly AS (
  SELECT * FROM _SQL
)

